// Get all items from Merge (Extract is index 0, Analysis is index 1)
const allItems = $input.all();

// Extract data from first item
const extractItem = allItems[0]?.json || {};
const contractData = extractItem.data || extractItem;

// Analysis data from second item
const analysisItem = allItems[1]?.json || {};
const riskAnalysis = analysisItem.markdown || analysisItem.answer || analysisItem.text || 'No analysis generated';

// Get trigger data for file info
const triggerData = $('New Data Room Doc').item.json;
const fileName = triggerData.name || 'unknown';
const fileId = triggerData.id || '';

// Format parties
const parties = contractData.parties || [];
const partiesList = parties.map(p => `${p.name} (${p.role})`).join(', ') || 'Not extracted';
const partyNames = parties.map(p => p.name).join(' / ') || 'Unknown';

// Change of control info
const coc = contractData.changeOfControl || {};
const cocStatus = coc.present ? 'Present' : 'Not Found';
const cocConsent = coc.consentRequired ? 'Required' : 'Not Required';
const cocTermRight = coc.terminationRight ? 'Yes' : 'No';

// Non-compete info
const nc = contractData.nonCompete || {};
const ncStatus = nc.present ? `${nc.duration || 'N/A'} / ${nc.geography || 'N/A'}` : 'None';

// Non-solicitation info
const ns = contractData.nonSolicitation || {};
const nsStatus = ns.present ? `${ns.duration || 'N/A'}` : 'None';

// Termination info
const term = contractData.terminationClauses || {};
const termNotice = term.noticePeriod || 'Not specified';

// IP info
const ip = contractData.ipProvisions || {};
const ipOwnership = ip.ownership || 'Not specified';

// Confidentiality
const conf = contractData.confidentiality || {};
const confSurvival = conf.survivalPeriod || 'Not specified';

// Consent requirements
const consents = contractData.consentRequirements || [];
const consentsList = consents.join(', ') || 'None identified';

// Compliance flags
const gdpr = contractData.gdprCompliance ? '✅ Present' : '❌ Missing';
const antiBribery = contractData.antiBriberyProvisions ? '✅ Present' : '❌ Missing';
const mac = contractData.macClause ? '✅ Present' : '❌ Missing';

// Determine risk level from analysis
let riskLevel = 'Low';
let criticalCount = 0;
let highCount = 0;

const analysisLower = riskAnalysis.toLowerCase();
criticalCount = (analysisLower.match(/critical/g) || []).length;
highCount = (analysisLower.match(/high/g) || []).length;

if (criticalCount >= 2) riskLevel = 'Critical';
else if (criticalCount >= 1 || highCount >= 3) riskLevel = 'High';
else if (highCount >= 1) riskLevel = 'Medium';

// Missing clauses summary
const missingClauses = [];
if (!contractData.gdprCompliance) missingClauses.push('GDPR');
if (!contractData.antiBriberyProvisions) missingClauses.push('Anti-Bribery');
if (!coc.present) missingClauses.push('Change of Control');
if (!contractData.macClause) missingClauses.push('MAC Clause');
if (!conf.present) missingClauses.push('Confidentiality');

const missingList = missingClauses.join(', ') || 'None';

return [{
  json: {
    documentType: contractData.documentType || 'Unknown',
    parties: partiesList,
    partyNames: partyNames,
    effectiveDate: contractData.effectiveDate || 'N/A',
    expirationDate: contractData.expirationDate || 'N/A',
    termLength: contractData.termLength || 'N/A',
    governingLaw: contractData.governingLaw || 'Not specified',
    contractValue: contractData.contractValue || 'Not disclosed',
    changeOfControlStatus: cocStatus,
    changeOfControlProvision: coc.provision || 'N/A',
    cocConsentRequired: cocConsent,
    cocTerminationRight: cocTermRight,
    nonCompete: ncStatus,
    nonSolicitation: nsStatus,
    terminationNotice: termNotice,
    assignmentRestrictions: contractData.assignmentRestrictions || 'None specified',
    ipOwnership: ipOwnership,
    confidentialitySurvival: confSurvival,
    indemnification: contractData.indemnification || 'Not specified',
    limitationOfLiability: contractData.limitationOfLiability || 'Not specified',
    consentRequirements: consentsList,
    gdprCompliance: gdpr,
    antiBribery: antiBribery,
    macClause: mac,
    dataProtection: contractData.dataProtectionProvisions || 'Not specified',
    missingClauses: missingList,
    missingCount: missingClauses.length,
    riskAnalysis: riskAnalysis,
    riskLevel: riskLevel,
    criticalIssues: criticalCount,
    highIssues: highCount,
    fileName: fileName,
    fileId: fileId,
    processedAt: new Date().toISOString()
  }
}];

